                'total_items': 0,
                'unique_items': 0
            }

        valid_prices = []
        total_quantity = 0

        for item in self.data:
            price = item.get('price')
            quantity = item.get('quantity', 0)

            if isinstance(price, (int, float)):
                valid_prices.append(float(price))

            if isinstance(quantity, (int, float)):
                total_quantity += int(quantity)

        if not valid_prices:
            return {
