                'max_price': 0.0,
                'min_price': 0.0,
                'total_items': total_quantity,
                'unique_items': len(self.data)
            }

        return {
            'avg_price': sum(valid_prices) / len(valid_prices),
            'max_price': max(valid_prices),
            'min_price': min(valid_prices),
            'total_items': total_quantity,
            'unique_items': len(self.data)
        }


